1071	/// Atomically writes `val` to `dst`.
1072	///
1073	/// This operation uses the `Release` ordering. If possible, an atomic instructions is used, and a
1074	/// global lock otherwise.
1075	unsafe fn atomic_store<T>(dst: *mut T, val: T) {
1076	    atomic! {
1077	        T, a,
1078	        {
1079	            a = unsafe { &*(dst as *const _ as *const _) };
1080	            a.store(unsafe { mem::transmute_copy(&val) }, Ordering::Release);
1081	            mem::forget(val);
1082	        },
1083	        {
1084	            let _guard = lock(dst as usize).write();
1085	            unsafe { ptr::write(dst, val) }
1086	        }
1087	    }
1088	}
1089	
1090	/// Atomically swaps data at `dst` with `val`.
1091	///
1092	/// This operation uses the `AcqRel` ordering. If possible, an atomic instructions is used, and a
1093	/// global lock otherwise.
1094	unsafe fn atomic_swap<T>(dst: *mut T, val: T) -> T {
1095	    atomic! {
1096	        T, a,
1097	        {
1098	            a = unsafe { &*(dst as *const _ as *const _) };
1099	            let res = unsafe { mem::transmute_copy(&a.swap(mem::transmute_copy(&val), Ordering::AcqRel)) };
1100	            mem::forget(val);
1101	            res
1102	        },
1103	        {
1104	            let _guard = lock(dst as usize).write();
1105	            unsafe { ptr::replace(dst, val) }
1106	        }
1107	    }
1108	}
