387	    /// Spawns a scoped thread with this configuration.
388	    ///
389	    /// The scoped thread is passed a reference to this scope as an argument, which can be used for
390	    /// spawning nested threads.
391	    ///
392	    /// The returned handle can be used to manually join the thread before the scope exits.
393	    ///
394	    /// # Errors
395	    ///
396	    /// Unlike the [`Scope::spawn`] method, this method yields an
397	    /// [`io::Result`] to capture any failure to create the thread at
398	    /// the OS level.
399	    ///
400	    /// [`io::Result`]: std::io::Result
401	    ///
402	    /// # Panics
403	    ///
404	    /// Panics if a thread name was set and it contained null bytes.
405	    ///
406	    /// # Examples
407	    ///
408	    /// ```
409	    /// use crossbeam_utils::thread;
410	    ///
411	    /// thread::scope(|s| {
412	    ///     let handle = s.builder()
413	    ///         .spawn(|_| {
414	    ///             println!("A child thread is running");
415	    ///             42
416	    ///         })
417	    ///         .unwrap();
418	    ///
419	    ///     // Join the thread and retrieve its result.
420	    ///     let res = handle.join().unwrap();
421	    ///     assert_eq!(res, 42);
422	    /// }).unwrap();
423	    /// ```
424	    pub fn spawn<F, T>(self, f: F) -> io::Result<ScopedJoinHandle<'scope, T>>
425	    where
426	        F: FnOnce(&Scope<'env>) -> T,
427	        F: Send + 'env,
428	        T: Send + 'env,
429	    {
430	        // The result of `f` will be stored here.
431	        let result = SharedOption::default();
432	
433	        // Spawn the thread and grab its join handle and thread handle.
434	        let (handle, thread) = {
435	            let result = Arc::clone(&result);
436	
437	            // A clone of the scope that will be moved into the new thread.
438	            let scope = Scope::<'env> {
439	                handles: Arc::clone(&self.scope.handles),
440	                wait_group: self.scope.wait_group.clone(),
441	                _marker: PhantomData,
442	            };
443	
444	            // Spawn the thread.
445	            let handle = {
446	                let closure = move || {
447	                    // Make sure the scope is inside the closure with the proper `'env` lifetime.
448	                    let scope: Scope<'env> = scope;
449	
450	                    // Run the closure.
451	                    let res = f(&scope);
452	
453	                    // Store the result if the closure didn't panic.
454	                    *result.lock().unwrap() = Some(res);
455	                };
456	
457	                // Allocate `closure` on the heap and erase the `'env` bound.
458	                let closure: Box<dyn FnOnce() + Send + 'env> = Box::new(closure);
459	                let closure: Box<dyn FnOnce() + Send + 'static> =
460	                    unsafe { mem::transmute(closure) };
461	
462	                // Finally, spawn the closure.
463	                self.builder.spawn(closure)?
464	            };
465	
466	            let thread = handle.thread().clone();
467	            let handle = Arc::new(Mutex::new(Some(handle)));
468	            (handle, thread)
469	        };
470	
471	        // Add the handle to the shared list of join handles.
472	        self.scope.handles.lock().unwrap().push(Arc::clone(&handle));
473	
474	        Ok(ScopedJoinHandle {
475	            handle,
476	            result,
477	            thread,
478	            _marker: PhantomData,
479	        })
480	    }
481	}
