9	/// A thread parking primitive.
10	///
11	/// Conceptually, each `Parker` has an associated token which is initially not present:
12	///
13	/// * The [`park`] method blocks the current thread unless or until the token is available, at
14	///   which point it automatically consumes the token.
15	///
16	/// * The [`park_timeout`] and [`park_deadline`] methods work the same as [`park`], but block for
17	///   a specified maximum time.
18	///
19	/// * The [`unpark`] method atomically makes the token available if it wasn't already. Because the
20	///   token is initially absent, [`unpark`] followed by [`park`] will result in the second call
21	///   returning immediately.
22	///
23	/// In other words, each `Parker` acts a bit like a spinlock that can be locked and unlocked using
24	/// [`park`] and [`unpark`].
25	///
26	/// # Examples
27	///
28	/// ```
29	/// use std::thread;
30	/// use std::time::Duration;
31	/// use crossbeam_utils::sync::Parker;
32	///
33	/// let p = Parker::new();
34	/// let u = p.unparker().clone();
35	///
36	/// // Make the token available.
37	/// u.unpark();
38	/// // Wakes up immediately and consumes the token.
39	/// p.park();
40	///
41	/// # let t =
42	/// thread::spawn(move || {
43	///     thread::sleep(Duration::from_millis(500));
44	///     u.unpark();
45	/// });
46	///
47	/// // Wakes up when `u.unpark()` provides the token.
48	/// p.park();
49	/// # t.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
50	/// ```
51	///
52	/// [`park`]: Parker::park
53	/// [`park_timeout`]: Parker::park_timeout
54	/// [`park_deadline`]: Parker::park_deadline
55	/// [`unpark`]: Unparker::unpark
56	pub struct Parker {
57	    unparker: Unparker,
58	    _marker: PhantomData<*const ()>,
59	}
60	
61	unsafe impl Send for Parker {}
