126	    pub fn park_timeout(&self, timeout: Duration) -> UnparkReason {
127	        match Instant::now().checked_add(timeout) {
128	            Some(deadline) => self.park_deadline(deadline),
129	            None => {
130	                self.park();
131	                UnparkReason::Unparked
132	            }
133	        }
