8	/// Enables threads to synchronize the beginning or end of some computation.
9	///
10	/// # Wait groups vs barriers
11	///
12	/// `WaitGroup` is very similar to [`Barrier`], but there are a few differences:
13	///
14	/// * [`Barrier`] needs to know the number of threads at construction, while `WaitGroup` is cloned to
15	///   register more threads.
16	///
17	/// * A [`Barrier`] can be reused even after all threads have synchronized, while a `WaitGroup`
18	///   synchronizes threads only once.
19	///
20	/// * All threads wait for others to reach the [`Barrier`]. With `WaitGroup`, each thread can choose
21	///   to either wait for other threads or to continue without blocking.
22	///
23	/// # Examples
24	///
25	/// ```
26	/// use crossbeam_utils::sync::WaitGroup;
27	/// use std::thread;
28	///
29	/// // Create a new wait group.
30	/// let wg = WaitGroup::new();
31	///
32	/// for _ in 0..4 {
33	///     // Create another reference to the wait group.
34	///     let wg = wg.clone();
35	///
36	///     thread::spawn(move || {
37	///         // Do some work.
38	///
39	///         // Drop the reference to the wait group.
40	///         drop(wg);
41	///     });
42	/// }
43	///
44	/// // Block until all threads have finished their work.
45	/// wg.wait();
46	/// # if cfg!(miri) { std::thread::sleep(std::time::Duration::from_millis(500)); } // wait for background threads closed: https://github.com/rust-lang/miri/issues/1371
47	/// ```
48	///
49	/// [`Barrier`]: std::sync::Barrier
50	pub struct WaitGroup {
51	    inner: Arc<Inner>,
52	}
53	
54	/// Inner state of a `WaitGroup`.
55	struct Inner {
56	    cvar: Condvar,
57	    lock: Mutex<()>,
58	    count: AtomicUsize,
59	}
60	
61	impl Default for WaitGroup {
62	    fn default() -> Self {
63	        Self {
64	            inner: Arc::new(Inner {
65	                cvar: Condvar::new(),
66	                lock: Mutex::new(()),
67	                count: AtomicUsize::new(1),
68	            }),
69	        }
70	    }
71	}
72	
73	impl WaitGroup {
74	    /// Creates a new wait group and returns the single reference to it.
75	    ///
76	    /// # Examples
77	    ///
78	    /// ```
79	    /// use crossbeam_utils::sync::WaitGroup;
80	    ///
81	    /// let wg = WaitGroup::new();
82	    /// ```
83	    pub fn new() -> Self {
84	        Self::default()
85	    }
86	
87	    /// Drops this reference and waits until all other references are dropped.
88	    ///
89	    /// # Examples
90	    ///
91	    /// ```
92	    /// use crossbeam_utils::sync::WaitGroup;
93	    /// use std::thread;
94	    ///
95	    /// let wg = WaitGroup::new();
96	    ///
97	    /// # let t =
98	    /// thread::spawn({
99	    ///     let wg = wg.clone();
100	    ///     move || {
101	    ///         // Block until both threads have reached `wait()`.
102	    ///         wg.wait();
103	    ///     }
104	    /// });
105	    ///
106	    /// // Block until both threads have reached `wait()`.
107	    /// wg.wait();
108	    /// # t.join().unwrap(); // join thread to avoid https://github.com/rust-lang/miri/issues/1371
109	    /// ```
110	    pub fn wait(self) {
111	        // SAFETY: this is equivalent to let Self { inner } = self, without calling our Drop.
112	        let inner = unsafe {
113	            let slf = ManuallyDrop::new(self);
114	            core::ptr::read(&slf.inner)
115	        };
116	
117	        if inner.count.fetch_sub(1, Ordering::AcqRel) == 1 {
118	            // Acquire lock after updating count, see below.
119	            drop(inner.lock.lock().unwrap());
120	            inner.cvar.notify_all();
121	            return;
122	        }
123	
124	        // We check the counter while holding the lock, and notifiers acquire
125	        // the lock between updating the counter and notifying, ensuring we
126	        // can not miss the notification.
127	        let mut guard = inner.lock.lock().unwrap();
128	        while inner.count.load(Ordering::Acquire) != 0 {
129	            guard = inner.cvar.wait(guard).unwrap();
130	        }
131	    }
132	}
133	
134	impl Drop for WaitGroup {
135	    fn drop(&mut self) {
136	        if self.inner.count.fetch_sub(1, Ordering::Release) == 1 {
137	            // Acquire lock after updating count, see wait().
138	            drop(self.inner.lock.lock().unwrap());
139	            self.inner.cvar.notify_all();
140	        }
141	    }
142	}
143	
144	impl Clone for WaitGroup {
145	    fn clone(&self) -> Self {
146	        self.inner.count.fetch_add(1, Ordering::Relaxed);
147	        Self {
148	            inner: self.inner.clone(),
149	        }
150	    }
151	}
152	
153	impl fmt::Debug for WaitGroup {
154	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
155	        let count = self.inner.count.load(Ordering::Relaxed);
156	        f.debug_struct("WaitGroup").field("count", &count).finish()
157	    }
158	}
