622	std::thread_local! {
623	    static REGISTRATION: Registration = {
624	        let thread_id = thread::current().id();
625	        let mut indices = thread_indices().lock().unwrap();
626	
627	        let index = match indices.free_list.pop() {
628	            Some(i) => i,
629	            None => {
630	                let i = indices.next_index;
631	                indices.next_index += 1;
632	                i
633	            }
634	        };
635	        indices.mapping.insert(thread_id, index);
636	
637	        Registration {
638	            index,
639	            thread_id,
640	        }
641	    };
642	}
