23	/// Number of bits needed to store height.
24	const HEIGHT_BITS: usize = 5;
25	
26	/// Maximum height of a skip list tower.
27	const MAX_HEIGHT: usize = 1 << HEIGHT_BITS;
28	
29	/// The bits of `refs_and_height` that keep the height.
30	const HEIGHT_MASK: usize = (1 << HEIGHT_BITS) - 1;
