32	/// The tower of atomic pointers.
33	///
34	/// The actual size of the tower will vary depending on the height that a node
35	/// was allocated with.
36	#[repr(C)]
37	struct Tower<K, V> {
38	    pointers: [Atomic<Node<K, V>>; 0],
39	}
