123	/// A skip list node.
124	///
125	/// This struct is marked with `repr(C)` so that the specific order of fields is enforced.
126	/// It is important that the tower is the last field since it is dynamically sized. The key,
127	/// reference count, and height are kept close to the tower to improve cache locality during
128	/// skip list traversal.
129	#[repr(C)]
130	struct Node<K, V> {
131	    /// The value.
132	    value: V,
133	
134	    /// The key.
135	    key: K,
136	
137	    /// Keeps the reference count and the height of its tower.
138	    ///
139	    /// The reference count is equal to the number of `Entry`s pointing to this node, plus the
140	    /// number of levels in which this node is installed.
141	    refs_and_height: AtomicUsize,
142	
143	    /// The tower of atomic pointers.
144	    tower: Tower<K, V>,
145	}
