163	impl<K, V> Node<K, V> {
164	    /// Allocates a node.
165	    ///
166	    /// The returned node will start with reference count of `ref_count` and the tower will be initialized
167	    /// with null pointers. However, the key and the value will be left uninitialized, and that is
168	    /// why this function is unsafe.
169	    unsafe fn alloc(height: usize, ref_count: usize) -> *mut Self {
170	        let layout = Self::get_layout(height);
171	        unsafe {
172	            let ptr = match Global.allocate(layout) {
173	                Some(ptr) => ptr.as_ptr().cast::<Self>(),
174	                None => handle_alloc_error(layout),
175	            };
176	
177	            ptr::addr_of_mut!((*ptr).refs_and_height)
178	                .write(AtomicUsize::new((height - 1) | (ref_count << HEIGHT_BITS)));
179	            ptr::addr_of_mut!((*ptr).tower.pointers)
180	                .cast::<Atomic<Self>>()
181	                .write_bytes(0, height);
182	            ptr
183	        }
184	    }
185	
186	    /// Deallocates a node.
187	    ///
188	    /// This function will not run any destructors.
189	    unsafe fn dealloc(ptr: *mut Self) {
190	        unsafe {
191	            let height = (*ptr).height();
192	            let layout = Self::get_layout(height);
193	            Global.deallocate(NonNull::new_unchecked(ptr.cast::<u8>()), layout);
194	        }
195	    }
196	
197	    /// Returns the layout of a node with the given `height`.
198	    fn get_layout(height: usize) -> Layout {
199	        assert!((1..=MAX_HEIGHT).contains(&height));
200	
201	        Layout::new::<Self>()
202	            .extend(Layout::array::<Atomic<Self>>(height).unwrap())
203	            .unwrap()
204	            .0
205	            .pad_to_align()
206	    }
207	
208	    /// Returns the height of this node's tower.
209	    #[inline]
210	    fn height(&self) -> usize {
211	        (self.refs_and_height.load(Ordering::Relaxed) & HEIGHT_MASK) + 1
212	    }
213	
214	    /// Attempts to increment the reference count of a node and returns `true` on success.
215	    ///
216	    /// The reference count can be incremented only if it is non-zero.
217	    ///
218	    /// # Panics
219	    ///
220	    /// Panics if the reference count overflows.
221	    #[inline]
222	    unsafe fn try_increment(&self) -> bool {
223	        let mut refs_and_height = self.refs_and_height.load(Ordering::Relaxed);
224	
225	        loop {
226	            // If the reference count is zero, then the node has already been
227	            // queued for deletion. Incrementing it again could lead to a
228	            // double-free.
229	            if refs_and_height & !HEIGHT_MASK == 0 {
230	                return false;
231	            }
232	
233	            // If all bits in the reference count are ones, we're about to overflow it.
234	            let new_refs_and_height = refs_and_height
235	                .checked_add(1 << HEIGHT_BITS)
236	                .expect("SkipList reference count overflow");
237	
238	            // Try incrementing the count.
239	            match self.refs_and_height.compare_exchange_weak(
240	                refs_and_height,
241	                new_refs_and_height,
242	                Ordering::Relaxed,
243	                Ordering::Relaxed,
244	            ) {
245	                Ok(_) => return true,
246	                Err(current) => refs_and_height = current,
247	            }
248	        }
249	    }
250	
251	    /// Drops the key and value of a node, then deallocates it.
252	    #[cold]
253	    unsafe fn finalize(ptr: *mut Self) {
254	        unsafe {
255	            // Call destructors: drop the key and the value.
256	            ptr::drop_in_place(&mut (*ptr).key);
257	            ptr::drop_in_place(&mut (*ptr).value);
258	
259	            // Finally, deallocate the memory occupied by the node.
260	            Self::dealloc(ptr);
261	        }
262	    }
263	}
