13	/// A set based on a lock-free skip list.
14	///
15	/// This is an alternative to [`BTreeSet`] which supports
16	/// concurrent access across multiple threads.
17	///
18	/// A custom comparator may be provided, causing all
19	/// elements to be ordered by the comparison function used
20	/// instead of the standard `Ord` impl. See [`Comparator`].
21	///
22	/// [`BTreeSet`]: std::collections::BTreeSet
23	/// [`Comparator`]: crate::comparator::Comparator
24	pub struct SkipSet<T, C = BasicComparator> {
25	    inner: map::SkipMap<T, (), C>,
26	}
