753	    /// If we encounter a deleted node while searching, help with the deletion
754	    /// by attempting to unlink the node from the list.
755	    ///
756	    /// If the unlinking is successful then this function returns the next node
757	    /// with which the search should continue on the current level.
758	    #[cold]
759	    unsafe fn help_unlink<'a>(
760	        &'a self,
761	        pred: &'a Atomic<Node<K, V>>,
762	        curr: NodeRef<'a, K, V>,
763	        succ: Shared<'a, Node<K, V>>,
764	        guard: &'a Guard,
765	    ) -> Option<Shared<'a, Node<K, V>>> {
766	        // If `succ` is marked, that means `curr` is removed. Let's try
767	        // unlinking it from the skip list at this level.
768	        match pred.compare_exchange(
769	            Shared::from(curr.ptr.as_ptr() as *const Node<K, V>),
770	            succ.with_tag(0),
771	            Ordering::Release,
772	            Ordering::Relaxed,
773	            guard,
774	        ) {
775	            Ok(_) => {
776	                unsafe { curr.decrement(guard) }
777	                Some(succ.with_tag(0))
778	            }
779	            Err(_) => None,
780	        }
781	    }
782	
783	    /// Returns the successor of a node.
784	    ///
785	    /// This will keep searching until a non-deleted node is found. If a deleted
786	    /// node is reached then a search is performed using the given key.
787	    fn next_node<'a>(
788	        &'a self,
789	        pred: TowerRef<'a, K, V>,
790	        lower_bound: Bound<&K>,
791	        guard: &'a Guard,
792	    ) -> Option<NodeRef<'a, K, V>> {
793	        unsafe {
794	            // Load the level 0 successor of the current node.
795	            let mut curr = pred.get_level(0).load_consume(guard);
796	
797	            // If `curr` is marked, that means `pred` is removed and we have to use
798	            // a key search.
799	            if curr.tag() == 1 {
800	                return self.search_bound(lower_bound, false, guard);
801	            }
802	
803	            while let Some(c) = NodeRef::from_shared(curr) {
804	                let succ = c.get_level(0).load_consume(guard);
805	
806	                if succ.tag() == 1 {
807	                    if let Some(c) = self.help_unlink(pred.get_level(0), c, succ, guard) {
808	                        // On success, continue searching through the current level.
809	                        curr = c;
810	                        continue;
811	                    } else {
812	                        // On failure, we cannot do anything reasonable to continue
813	                        // searching from the current position. Restart the search.
814	                        return self.search_bound(lower_bound, false, guard);
815	                    }
816	                }
817	
818	                return Some(c);
819	            }
820	
821	            None
822	        }
823	    }
